class Solution {
public:
    void moveZeroes(vector<int>& nums) {
        int n = nums.size(), left = 0, right = 0;
        while (right < n) {
            if (nums[right]) {
                swap(nums[left], nums[right]); // 不变量：left 左边全非零且保持原相对顺序
                left++;
            }
            right++;
        }
    }
};
